function isKSMOnOtherConsensusSystem(location) {
    return matchesConsensusSystem(location, "Kusama");
}
function isDOTOnOtherConsensusSystem(location) {
    return matchesConsensusSystem(location, "Polkadot");
}
function isDOT(location) {
    if (location.parents !== 1 || !location.interior)
        return false;
    if (location.interior !== "Here" && location.interior !== "here")
        return false;
    return true;
}
function matchesConsensusSystem(location, expectedSystem) {
    if (location.parents !== 2 || !location.interior)
        return false;
    const kind = Object.keys(location.interior).find((k) => k.toLowerCase() === "x1");
    if (!kind)
        return false;
    const values = location.interior[kind];
    if (!Array.isArray(values) || values.length === 0)
        return false;
    const consensus = values[0];
    const consensusKey = Object.keys(consensus || {}).find((k) => k.toLowerCase() === "globalconsensus");
    if (!consensusKey)
        return false;
    const consensusValue = consensus[consensusKey];
    return (typeof consensusValue === "object" &&
        Object.keys(consensusValue).some((k) => k.toLowerCase() === expectedSystem.toLowerCase()));
}
function isEthereumAsset(location) {
    if (location.parents !== 2 || !location.interior)
        return false;
    const interior = location.interior;
    const kind = Object.keys(interior).find((k) => k.toLowerCase() === "x1" || k.toLowerCase() === "x2");
    if (!kind)
        return false;
    const values = interior[kind];
    if (!Array.isArray(values) || values.length === 0)
        return false;
    const consensus = values[0];
    const consensusKey = Object.keys(consensus || {}).find((k) => k.toLowerCase() === "globalconsensus");
    if (!consensusKey)
        return false;
    const consensusValue = consensus[consensusKey];
    return (typeof consensusValue === "object" &&
        Object.keys(consensusValue).some((k) => k.toLowerCase() === "ethereum"));
}
function isRelaychainLocation(location) {
    return location.parents == exports.DOT_LOCATION.parents && location.interior == exports.DOT_LOCATION.interior;
}
